    val n = nums.size
    if (n == 0) return 0L

    val dp = LongArray(n + 1)
    dp[0] = 0L

    val modMap = HashMap<Long, Long>()
    modMap[0L] = 0L

    var prefixMod = 0L

    for (i in 1..n) {
        prefixMod = (prefixMod + nums[i - 1]) % k
        val currentMod = prefixMod

        var minPrev = Long.MAX_VALUE
        if (modMap.containsKey(currentMod)) {
            minPrev = modMap[currentMod]!!
        }

        val option1 = dp[i - 1] + nums[i - 1]
        val option2 = minPrev
        dp[i] = min(option1, option2)

        if (modMap.containsKey(currentMod)) {
            if (dp[i] < modMap[currentMod]!!) {
                modMap[currentMod] = dp[i]
            }
        } else {
            modMap[currentMod] = dp[i]
        }
